function dropRate(e){let r=e.boss?.65:e.rare?.08:.012;return Math.min(.85,r+(effects().drop||0))}function stoneDrop(e){let n=1;if(Math.random()<.2)n++;if(e.rare)n+=3+Math.floor(Math.random()*6);if(e.boss)n+=20;if(e.metal)n+=10;n+=Math.floor(n*(effects().stoneBoost||0));return n}
function level(ch){while(ch.exp>=ch.next){ch.exp-=ch.next;ch.lv++;ch.next=Math.floor(ch.next*1.16+ch.lv*42+170);ch.maxHp=Math.floor(ch.maxHp*1.17+70);ch.maxMp=Math.floor(ch.maxMp*1.13+28);ch.atk=Math.floor(ch.atk*1.16+18);ch.def=Math.floor(ch.def*1.13+12);ch.hp=total(ch).maxHp;ch.mp=total(ch).maxMp;log(`${ch.name} Lv${ch.lv}!`,'rare');sfx('level')}}function syncAlly(){const h=state.hero,a=state.ally;a.lv=h.lv;a.next=h.next;a.maxHp=Math.max(a.maxHp,Math.floor(h.maxHp*.82));a.maxMp=Math.max(a.maxMp,Math.floor(h.maxMp*1.15));a.atk=Math.max(a.atk,Math.floor(h.atk*.72));a.def=Math.max(a.def,Math.floor(h.def*.78));a.hp=Math.min(total(a).maxHp,Math.max(a.hp,Math.floor(total(a).maxHp*.72)));a.mp=Math.min(total(a).maxMp,Math.max(a.mp,Math.floor(total(a).maxMp*.72)))}
function addProgress(id,p){state.progress[id]=(state.progress[id]||0)+p;const st=DATA.stages.find(s=>s.id===id);if(!state.completed[id]&&state.progress[id]>=st.progressTarget){state.completed[id]=true;log(`${st.name}進捗100%。強力な永続バフ解放!`,'rare');toast(`${st.name} 永続バフ解放`);sfx('progress')}}function progressRate(id){const st=DATA.stages.find(s=>s.id===id);return Math.min(100,((state.progress[id]||0)/st.progressTarget)*100)}
function addStone(id,c){state.stones[id]=(state.stones[id]||0)+c}function totalStones(){return Object.values(state.stones).reduce((a,b)=>a+b,0)}function consumeStones(mode){let total=totalStones();if(total<=0)return[];let need=mode==='all'?total:Math.max(1,Math.floor(total*Number(mode)/100));let arr=Object.entries(state.stones).filter(([,c])=>c>0).sort((a,b)=>enemyById(b[0]).stonePower-enemyById(a[0]).stonePower),used=[];for(const [id,c] of arr){if(need<=0)break;let n=Math.min(c,need);state.stones[id]-=n;need-=n;used.push({id,count:n})}return used}
function threshold(e,stat){const base={maxHp:1300,maxMp:450,atk:160,def:120}[stat]||100;return Math.floor(e.stonePower*base*(e.rare?1.8:1)*(e.boss?6:1))}function rate(cur,th){if(cur<th)return 1;if(cur<th*3)return .34;if(cur<th*10)return .12;if(cur<th*30)return .045;return .018}function statGain(e,c,stat,raw,cur){return Math.max(1,Math.floor(raw*c*rate(cur,threshold(e,stat))))}
