function buy(id){const it=item(id);if(!it)return;if(state.gold<it.price){log('G不足','bad');return}state.gold-=it.price;state.inventory[id]=(state.inventory[id]||0)+1;log(`${it.name}購入`,'good');sfx('coin');render()}function equip(who,id){const it=item(id),ch=actor(who);if(!it||!ch)return;if((state.inventory[id]||0)<=0){log('未所持','bad');return}ch.equip[it.slot]=id;ch.hp=Math.min(ch.hp,total(ch).maxHp);ch.mp=Math.min(ch.mp,total(ch).maxMp);log(`${ch.name}: ${it.name}装備`,'good');sfx('equip');render()}
